import React, { useState } from "react";

const NoteModal = ({ note, isOpen, onClose, onSave }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedTitle, setEditedTitle] = useState(note?.title || "");
  const [editedContent, setEditedContent] = useState(note?.content || "");

  const handleSave = () => {
    onSave({
      ...note,
      title: editedTitle,
      content: editedContent,
    }); 
    setIsEditing(false);
    onClose();
  };

  const handleCancel = () => {
    setEditedTitle(note?.title || "");
    setEditedContent(note?.content || "");
    setIsEditing(false);
  };

  if (!isOpen || !note) return null;

  return (
    <div
      className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50"
      onClick={onClose}
    >
      <div
        className="bg-white rounded-lg shadow-xl max-w-md w-full mx-4 p-6"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Close Button */}
        <button
          onClick={onClose}
          className="absolute top-4 right-4 text-gray-500 hover:text-gray-700 text-xl"
        >
          ✕
        </button>

        {/* Title */}
        {isEditing ? (
          <input
            type="text"
            value={editedTitle}
            onChange={(e) => setEditedTitle(e.target.value)}
            className="w-full text-2xl font-bold text-gray-800 mb-4 border-b-2 border-gray-300 focus:border-indigo-500 outline-none"
            placeholder="Note Title"
          />
        ) : (
          <h2 className="text-2xl font-bold text-gray-800 mb-4">
            {note.title}
          </h2>
        )}

        {/* Content */}
        {isEditing ? (
          <textarea
            value={editedContent}
            onChange={(e) => setEditedContent(e.target.value)}
            className="w-full h-32 p-2 border border-gray-300 rounded-lg focus:border-indigo-500 outline-none resize-none"
            placeholder="Note Content"
          />
        ) : (
          <p className="text-gray-700 mb-6 whitespace-pre-wrap">
            {note.content}
          </p>
        )}

        {/* Buttons */}
        <div className="flex space-x-3">
          {isEditing ? (
            <>
              <button
                onClick={handleSave}
                className="flex-1 bg-green-600 text-white py-2 px-4 rounded-lg font-semibold hover:bg-green-700 transition-colors duration-200"
              >
                Save
              </button>
              <button
                onClick={handleCancel}
                className="flex-1 bg-gray-300 text-gray-800 py-2 px-4 rounded-lg font-semibold hover:bg-gray-400 transition-colors duration-200"
              >
                Cancel
              </button>
            </>
          ) : (
            <button
              onClick={() => setIsEditing(true)}
              className="flex-1 bg-indigo-600 text-white py-2 px-4 rounded-lg font-semibold hover:bg-indigo-700 transition-colors duration-200"
            >
              Edit
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default NoteModal;
